    ["GGW_Instructions2"] = { name = "GGW_Instructions2", type = "Label", x = 50, y = 50, w = 300, h = 200, anim = nil, text = "Match 3 or more gems in a horizontal, vertical, or diagonal line to score points and remove those matching gems from play.  The more gems matched at once, the higher your score.  Match 4 or more blue gems to activate good special play modes, but only 3 or more red gems matched will activate bad special play modes.  The game ends when a column reaches the top of the playfield.", rel = true, anchor = { TopAnchorToTop = false, TopAnchorToBottom = false, BottomAnchorToTop = false, BottomAnchorToBottom = false, LeftAnchorToLeft = false, LeftAnchorToRight = false, RightAnchorToLeft = false, RightAnchorToRight = false, TopAnchorOffset = 0, BottomAnchorOffset = 0, LeftAnchorOffset = 0, RightAnchorOffset = 0, AutoStretch = false }, gauge = nil, spellgem = nil },
